import React from 'react';
import { useConversation } from './hooks/useConversation';
import ChatBubble from './components/ChatBubble';
import InputArea from './components/InputArea';

function App() {
  // Pulling the logic from your custom hook
  const { messages, isTyping, currentStep, handleUserAnswer } = useConversation();

  return (
  <div className="min-h-screen bg-[#fcfcfd] flex flex-col items-center justify-center p-6 font-sans">
    
    {/* Subtle Progress Tracker */}
    <div className="fixed top-12 w-full max-w-md px-12">
      <div className="h-1 w-full bg-slate-100 rounded-full overflow-hidden">
        <div 
          className="h-full bg-emerald-500 transition-all duration-1000 ease-out"
          style={{ width: `${(messages.filter(m => m.sender === 'bot').length / 5) * 100}%` }}
        />
      </div>
      <p className="text-[10px] text-center mt-3 uppercase tracking-widest text-slate-400 font-bold">
        Session Progress
      </p>
    </div>

    {/* The Main Stage */}
    <main className="w-full max-w-4xl flex flex-col items-center text-center">
      
      <div className="min-h-[160px] flex items-center justify-center mb-12">
        {isTyping ? (
          <div className="flex gap-2">
            <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
            <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
            <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
          </div>
        ) : (
          <h1 className="text-4xl md:text-5xl font-semibold text-slate-800 leading-tight tracking-tight animate-in fade-in slide-in-from-bottom-8 duration-1000">
            {messages.filter(m => m.sender === 'bot').slice(-1)[0]?.text}
          </h1>
        )}
      </div>

      <InputArea 
        currentStep={currentStep} 
        onSendMessage={handleUserAnswer} 
        isTyping={isTyping} 
      />
    </main>

    {/* Professional Footer */}
    <footer className="fixed bottom-12 text-slate-300 text-[11px] uppercase tracking-[3px] font-medium">
      NIMHANS Clinical Protocol • Confidential
    </footer>
  </div>
);
}

export default App;
